// n8n'in kalıcı hafızasını çağırıyoruz
const staticData = $getWorkflowStaticData('global');
staticData.gonderilenler = staticData.gonderilenler || [];

// Versiyona göre veri girişini yakalama (input ya da $input kullanımı)
const incomingItems = (typeof input !== 'undefined' && input.all) ? input.all() : (typeof $input !== 'undefined' && $input.all) ? $input.all() : [];

// Sadece daha önce gönderilmemiş (hafızada olmayan) linkleri filtrele
const yeniIlanlar = incomingItems.filter(item => {
  const link = item.json.link;
  return link && !staticData.gonderilenler.includes(link);
});

// Yeni ilanların linklerini hafızaya kaydet (bir sonraki sefer tekrar gitmesinler diye)
yeniIlanlar.forEach(item => {
  staticData.gonderilenler.push(item.json.link);
});

// Hafızanın şişmesini önlemek için sadece son 500 linki tutalım
if (staticData.gonderilenler.length > 500) {
  staticData.gonderilenler = staticData.gonderilenler.slice(-500);
}

// Sadece yeni olan ilanları bir sonraki adıma (Telegram'a) gönder
return yeniIlanlar;
